-- 애터미 수당체계 학습 퀴즈 — 3단계 문제 확장 마이그레이션 (100문항 추가 + 기존 N가 표현 정리)
-- 전제: supabase-schema-questions-cms.sql이 이미 실행되어 있어야 합니다.
-- 사용 방법: Supabase 대시보드 > SQL Editor > New query 에 전체를 붙여넣고 실행하세요.

-- 1) N가는 변동값이므로 "현재 N가는 얼마인가?" 식의 암기형 문제 2개를 삭제합니다.
delete from public.questions where id in ('q032', 'q122');

-- 2) 기존 계산 문제의 "현재 N가(3,502원)" 표현을 "N가를 3,502원이라고 가정할 때"로 정리합니다.
update public.questions set question = $q$N가를 3,502원이라고 가정할 때, 15점을 취득했다면 후원수당 금액은 얼마인가?$q$, explanation = $q$15점 × 3,502원 = 52,530원이다.$q$, updated_at = now() where id = 'q033';
update public.questions set question = $q$N가를 3,502원이라고 가정할 때, 15점 기준 후원수당은 대략 얼마인가?$q$, explanation = $q$15점 × 3,502원 = 52,530원으로 약 5.2만원이다.$q$, updated_at = now() where id = 'q037';
update public.questions set question = $q$N가를 3,502원이라고 가정할 때, 30점을 취득했다면 후원수당 금액은 얼마인가?$q$, explanation = $q$30점 × 3,502원 = 105,060원이다.$q$, updated_at = now() where id = 'q040';
update public.questions set question = $q$본인 등급이 '회원'인 사람이 8급 점수(5점)를 취득했다. N가를 3,502원이라고 가정할 때 후원수당 금액은 얼마인가? (단위: 원, 콤마 없이 숫자만 입력)$q$, explanation = $q$5점 × 3,502원 = 17,510원$q$, updated_at = now() where id = 'q137';
update public.questions set question = $q$5급(60점)을 취득했다. N가를 3,502원이라고 가정할 때 후원수당 금액은 얼마인가? (숫자만 입력)$q$, explanation = $q$60점 × 3,502원 = 210,120원$q$, updated_at = now() where id = 'q138';
update public.questions set question = $q$4급(90점)을 취득했다. N가를 3,502원이라고 가정할 때 후원수당 금액은 얼마인가? (숫자만 입력)$q$, explanation = $q$90점 × 3,502원 = 315,180원$q$, updated_at = now() where id = 'q139';
update public.questions set question = $q$3급(150점)을 취득했다. N가를 3,502원이라고 가정할 때 후원수당 금액은 얼마인가? (숫자만 입력)$q$, explanation = $q$150점 × 3,502원 = 525,300원$q$, updated_at = now() where id = 'q140';
update public.questions set question = $q$2급(250점)을 취득했다. N가를 3,502원이라고 가정할 때 후원수당 금액은 얼마인가? (숫자만 입력)$q$, explanation = $q$250점 × 3,502원 = 875,500원$q$, updated_at = now() where id = 'q141';
update public.questions set question = $q$1급(300점)을 취득했다. N가를 3,502원이라고 가정할 때 후원수당 금액은 얼마인가? (숫자만 입력)$q$, explanation = $q$300점 × 3,502원 = 1,050,600원$q$, updated_at = now() where id = 'q142';
update public.questions set question = $q$본인 등급이 '회원'인 사람이 소실적 30만 PV 달성으로 5점을 두 차례 취득했다. 합산 점수 기준, N가를 3,502원이라고 가정할 때 후원수당 금액은 얼마인가? (숫자만 입력)$q$, explanation = $q$5점 + 5점 = 10점, 10점 × 3,502원 = 35,020원$q$, updated_at = now() where id = 'q147';

-- 3) 신규 문제 100개(q157~q256)를 추가합니다.
on conflict (id) do nothing;
